#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` but allow `pnpm test:ci` and other variants
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd and not any(flag in cmd for flag in ["--run", "--reporter"]):
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and will timeout.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re, ast

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    # Only check Edit/Write on Python files
    if tool not in ["Edit", "Write"]:
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Get the new content
    content = None
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        # For Edit, we need to reconstruct or read the file
        # Since we're PostToolUse, the file has been written
        try:
            with open(file_path, 'r') as f:
                content = f.read()
        except Exception:
            return 0

    if not content:
        return 0

    # Parse and detect recursion
    try:
        tree = ast.parse(content)
    except SyntaxError:
        return 0  # Let other tools handle syntax errors

    recursive_funcs = []

    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            func_name = node.name
            # Check if function calls itself
            for child in ast.walk(node):
                if isinstance(child, ast.Call):
                    if isinstance(child.func, ast.Name) and child.func.id == func_name:
                        recursive_funcs.append(func_name)
                        break

    if recursive_funcs:
        funcs_str = ", ".join(recursive_funcs)
        print(f"REQUIRED FOLLOW-UP: Recursive function(s) detected: {funcs_str}. Python's recursion limit is ~1000 frames. If this processes large data structures (>1000 items), rewrite as iterative (stack/queue-based). Fix now if needed, then proceed. Do not stop until verified safe.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/Write on Python files, run ruff format + ruff check and feed back any errors."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    if tool not in ("Edit", "Write"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff format first
    try:
        format_result = subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )
    except Exception:
        return 0

    # Then run ruff check
    try:
        check_result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )
    except Exception:
        return 0

    # If there are linting errors, feed them back
    if check_result.returncode != 0:
        errors = check_result.stdout + check_result.stderr
        print(f"REQUIRED FOLLOW-UP: ruff check found {errors.count('error')} errors in {file_path}:", file=sys.stderr)
        for line in errors.strip().split("\n")[:10]:
            if line.strip():
                print(f"  {line}", file=sys.stderr)
        print("Fix each error, then re-run ruff check. Do not stop until clean.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for callers and feed the list back to Claude so it can verify consistency."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"REQUIRED FOLLOW-UP: export `{name}` was edited. {len(hits)} references found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Update each reference to match the new value, then proceed. Do not stop until done.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check Write and Edit operations
    if tool not in ["Write", "Edit"]:
        return 0

    # Get the content being written
    content = ""
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        content = inp.get("new_string", "")

    if not content:
        return 0

    # Secret patterns to detect
    patterns = [
        (r'sk-[a-zA-Z0-9]{20,}', "OpenAI API key"),
        (r'AIzaSy[a-zA-Z0-9_-]{33}', "Google API key"),
        (r'ghp_[a-zA-Z0-9]{36}', "GitHub personal access token"),
        (r'gho_[a-zA-Z0-9]{36}', "GitHub OAuth token"),
        (r'xoxb-[0-9]{10,13}-[0-9]{10,13}-[a-zA-Z0-9]{24}', "Slack bot token"),
        (r'AKIA[0-9A-Z]{16}', "AWS access key"),
        (r'["\']?password["\']?\s*[:=]\s*["\'][^"\']{8,}["\']', "hardcoded password"),
        (r'["\']?api[_-]?key["\']?\s*[:=]\s*["\'][^"\']{16,}["\']', "hardcoded API key"),
    ]

    for pattern, desc in patterns:
        if re.search(pattern, content, re.IGNORECASE):
            print(f"BLOCKED: Detected {desc} hardcoded in file content. Secrets must come from process.env per CLAUDE.md. Read from environment variables instead.", file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block commit messages that are paragraphs; enforce short imperative subject lines."""
import json, re, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Bash":
        return 0

    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")

    # Match git commit with -m flag
    if not re.search(r'\bgit\s+commit\b', cmd):
        return 0

    # Extract message from -m "..." or -m '...'
    msg_match = re.search(r'-m\s+["\'](.+?)["\']', cmd, re.DOTALL)
    if not msg_match:
        return 0  # No -m flag or can't parse

    msg = msg_match.group(1).strip()

    # Check for paragraph-style violations
    lines = msg.split('\n')
    subject = lines[0].strip()

    # Violations:
    # 1. Subject line is a full sentence (ends with period)
    # 2. Subject line is too long (>72 chars is a warning sign)
    # 3. Subject starts with "This commit" or "This change"
    if subject.endswith('.'):
        print("Commit message subject line ends with a period — use imperative mood without terminal punctuation.\nExample: 'Refactor auth: extract token validation' (not 'This commit refactors the authentication module.')", file=sys.stderr)
        return 2

    if len(subject) > 72:
        print(f"Commit message subject line is {len(subject)} chars (>72) — keep it short and imperative.\nExample: 'Refactor auth: extract token validation'", file=sys.stderr)
        return 2

    if re.match(r'^(this commit|this change|this)\s', subject, re.IGNORECASE):
        print("Commit message starts with 'This commit/change' — use imperative mood.\nExample: 'Refactor auth: extract token validation' (not 'This commit refactors...')", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
